import React, { useEffect, useState } from 'react';
import axios from 'axios';

export default function AdminFees() {
  const [fees, setFees] = useState([]);
  const [total, setTotal] = useState(0);
  const [page, setPage] = useState(1);
  const [pages, setPages] = useState(1);
  const [filterStatus, setFilterStatus] = useState('');
  const [filterMonth, setFilterMonth] = useState('');
  const [msg, setMsg] = useState({ text: '', type: '' });
  const [selectedFee, setSelectedFee] = useState(null);
  const [showPayModal, setShowPayModal] = useState(false);
  const [showGenModal, setShowGenModal] = useState(false);
  const [showReceiptModal, setShowReceiptModal] = useState(false);
  const [payForm, setPayForm] = useState({ paymentMode: 'cash', transactionId: '', lateFee: 0, discount: 0, remarks: '' });
  const [genForm, setGenForm] = useState({ feeMonth: new Date().toISOString().slice(0, 7), dueDate: '' });

  const fetchFees = async () => {
    try {
      const r = await axios.get('/fees', { params: { page, limit: 15, status: filterStatus, feeMonth: filterMonth } });
      setFees(r.data.fees); setTotal(r.data.total); setPages(r.data.pages);
    } catch (e) { console.error(e); }
  };

  useEffect(() => { fetchFees(); }, [page, filterStatus, filterMonth]);

  const notify = (text, type = 'success') => { setMsg({ text, type }); setTimeout(() => setMsg({ text: '', type: '' }), 3000); };

  const handleCollect = async (e) => {
    e.preventDefault();
    try {
      await axios.put(`/fees/${selectedFee.id}/collect`, payForm);
      notify('Payment recorded successfully!');
      setShowPayModal(false); fetchFees();
    } catch (err) { notify(err.response?.data?.message || 'Error', 'error'); }
  };

  const handleGenerate = async (e) => {
    e.preventDefault();
    try {
      const r = await axios.post('/fees/generate', genForm);
      notify(`${r.data.message}. Students have been notified.`);
      setShowGenModal(false); fetchFees();
    } catch (err) { notify(err.response?.data?.message || 'Error generating fees', 'error'); }
  };

  const statusColor = { paid: 'badge-paid', pending: 'badge-pending', overdue: 'badge-overdue', waived: 'badge-waived' };
  const fmt = (n) => `₹${Number(n || 0).toLocaleString('en-IN')}`;

  return (
    <div>
      {msg.text && <div className={`alert alert-${msg.type === 'error' ? 'error' : 'success'}`}>{msg.text}</div>}
      <div className="search-bar">
        <input type="month" className="filter-select" value={filterMonth} onChange={e => { setFilterMonth(e.target.value); setPage(1); }} style={{ width: 160 }} />
        <select className="filter-select" value={filterStatus} onChange={e => { setFilterStatus(e.target.value); setPage(1); }}>
          <option value="">All Status</option>
          <option value="pending">Pending</option>
          <option value="paid">Paid</option>
          <option value="overdue">Overdue</option>
          <option value="waived">Waived</option>
        </select>
        <button className="btn btn-primary" onClick={() => setShowGenModal(true)}>⚡ Generate Monthly Fees</button>
      </div>

      <div className="card">
        <div className="card-header">
          <h3 className="card-title">Fee Records ({total})</h3>
          <span style={{ fontSize: 12, color: 'var(--text-muted)' }}>{filterMonth || 'All months'}</span>
        </div>
        <div className="table-wrap">
          <table>
            <thead><tr><th>Student</th><th>Route</th><th>Month</th><th>Amount</th><th>Late Fee</th><th>Total</th><th>Due Date</th><th>Status</th><th>Actions</th></tr></thead>
            <tbody>
              {fees.length === 0 ? (
                <tr><td colSpan={9}><div className="empty-state"><span className="icon">💰</span><p>No fee records found</p></div></td></tr>
              ) : fees.map(f => (
                <tr key={f.id}>
                  <td>
                    <div style={{ fontWeight: 600 }}>{f.student?.user?.name}</div>
                    <div style={{ fontSize: 11, color: 'var(--text-muted)' }}>{f.student?.studentId}</div>
                  </td>
                  <td style={{ fontSize: 12 }}>{f.route?.routeNumber}</td>
                  <td style={{ fontSize: 12 }}>{f.feeMonth}</td>
                  <td>{fmt(f.amount)}</td>
                  <td style={{ color: f.lateFee > 0 ? 'var(--danger)' : 'inherit' }}>{f.lateFee > 0 ? fmt(f.lateFee) : '—'}</td>
                  <td><strong>{fmt(f.totalAmount)}</strong></td>
                  <td style={{ fontSize: 12 }}>{f.dueDate}</td>
                  <td><span className={`badge ${statusColor[f.status]}`}>{f.status}</span></td>
                  <td>
                    <div style={{ display: 'flex', gap: 4 }}>
                      {f.status === 'pending' || f.status === 'overdue' ? (
                        <button className="btn btn-success btn-sm" onClick={() => { setSelectedFee(f); setPayForm({ paymentMode: 'cash', transactionId: '', lateFee: f.lateFee || 0, discount: 0, remarks: '' }); setShowPayModal(true); }}>💳 Collect</button>
                      ) : f.status === 'paid' ? (
                        <button className="btn btn-outline btn-sm" onClick={() => { setSelectedFee(f); setShowReceiptModal(true); }}>🧾 Receipt</button>
                      ) : null}
                    </div>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
        <div className="pagination">
          <span>Showing {fees.length} of {total}</span>
          <div className="page-btns">
            <button className="page-btn" onClick={() => setPage(p => p - 1)} disabled={page === 1}>‹</button>
            {Array.from({ length: Math.min(pages, 5) }, (_, i) => i + 1).map(p => <button key={p} className={`page-btn ${page === p ? 'active' : ''}`} onClick={() => setPage(p)}>{p}</button>)}
            <button className="page-btn" onClick={() => setPage(p => p + 1)} disabled={page === pages}>›</button>
          </div>
        </div>
      </div>

      {/* Generate Fees Modal */}
      {showGenModal && (
        <div className="modal-overlay" onClick={e => e.target === e.currentTarget && setShowGenModal(false)}>
          <div className="modal" style={{ maxWidth: 400 }}>
            <div className="modal-header"><h3 className="modal-title">⚡ Generate Monthly Fees</h3><button className="modal-close" onClick={() => setShowGenModal(false)}>×</button></div>
            <form onSubmit={handleGenerate}>
              <div className="form-group"><label>Fee Month *</label><input type="month" value={genForm.feeMonth} onChange={e => setGenForm({ ...genForm, feeMonth: e.target.value })} required /></div>
              <div className="form-group"><label>Due Date *</label><input type="date" value={genForm.dueDate} onChange={e => setGenForm({ ...genForm, dueDate: e.target.value })} required /></div>
              <p style={{ fontSize: 12, color: 'var(--text-muted)', marginBottom: 16 }}>This will generate pending fee records for all active students on assigned routes.</p>
              <div style={{ display: 'flex', gap: 10 }}>
                <button type="submit" className="btn btn-primary" style={{ flex: 1, justifyContent: 'center' }}>Generate Fees</button>
                <button type="button" className="btn btn-outline" onClick={() => setShowGenModal(false)}>Cancel</button>
              </div>
            </form>
          </div>
        </div>
      )}

      {/* Collect Payment Modal */}
      {showPayModal && selectedFee && (
        <div className="modal-overlay" onClick={e => e.target === e.currentTarget && setShowPayModal(false)}>
          <div className="modal" style={{ maxWidth: 440 }}>
            <div className="modal-header"><h3 className="modal-title">💳 Collect Payment</h3><button className="modal-close" onClick={() => setShowPayModal(false)}>×</button></div>
            <div style={{ background: 'var(--surface2)', border: '1px solid var(--border)', borderRadius: 10, padding: 14, marginBottom: 18, fontSize: 13 }}>
              <div><strong>Student:</strong> {selectedFee.student?.user?.name}</div>
              <div><strong>Month:</strong> {selectedFee.feeMonth} | <strong>Base Amount:</strong> ₹{selectedFee.amount}</div>
            </div>
            <form onSubmit={handleCollect}>
              <div className="form-row">
                <div className="form-group"><label>Payment Mode *</label><select value={payForm.paymentMode} onChange={e => setPayForm({ ...payForm, paymentMode: e.target.value })}><option value="cash">Cash</option><option value="online">Online</option><option value="cheque">Cheque</option><option value="dd">DD</option></select></div>
                <div className="form-group"><label>Late Fee (₹)</label><input type="number" min="0" value={payForm.lateFee} onChange={e => setPayForm({ ...payForm, lateFee: e.target.value })} /></div>
              </div>
              <div className="form-row">
                <div className="form-group"><label>Discount (₹)</label><input type="number" min="0" value={payForm.discount} onChange={e => setPayForm({ ...payForm, discount: e.target.value })} /></div>
                <div className="form-group"><label>Transaction ID</label><input value={payForm.transactionId} onChange={e => setPayForm({ ...payForm, transactionId: e.target.value })} /></div>
              </div>
              <div className="form-group"><label>Remarks</label><input value={payForm.remarks} onChange={e => setPayForm({ ...payForm, remarks: e.target.value })} /></div>
              <div style={{ background: '#f0fdf4', border: '1px solid #bbf7d0', borderRadius: 8, padding: 12, marginBottom: 14, textAlign: 'center', fontWeight: 700, fontSize: 15 }}>
                Total: ₹{(Number(selectedFee.amount) + Number(payForm.lateFee) - Number(payForm.discount)).toLocaleString()}
              </div>
              <div style={{ display: 'flex', gap: 10 }}>
                <button type="submit" className="btn btn-success" style={{ flex: 1, justifyContent: 'center' }}>✅ Confirm Payment</button>
                <button type="button" className="btn btn-outline" onClick={() => setShowPayModal(false)}>Cancel</button>
              </div>
            </form>
          </div>
        </div>
      )}

      {/* Receipt Modal */}
      {showReceiptModal && selectedFee && (
        <div className="modal-overlay" onClick={e => e.target === e.currentTarget && setShowReceiptModal(false)}>
          <div className="modal" style={{ maxWidth: 400 }}>
            <div className="modal-header"><h3 className="modal-title">🧾 Payment Receipt</h3><button className="modal-close" onClick={() => setShowReceiptModal(false)}>×</button></div>
            <div className="receipt">
              <div className="receipt-header">
                <div style={{ fontSize: 22 }}>🚌</div>
                <div style={{ fontWeight: 700, fontSize: 16 }}>Campus Bus Services</div>
                <div style={{ fontSize: 11, color: 'var(--text-muted)' }}>Fee Payment Receipt</div>
              </div>
              <div className="receipt-row"><span>Receipt No:</span><strong>{selectedFee.receiptNumber}</strong></div>
              <div className="receipt-row"><span>Student:</span><span>{selectedFee.student?.user?.name}</span></div>
              <div className="receipt-row"><span>Student ID:</span><span>{selectedFee.student?.studentId}</span></div>
              <div className="receipt-row"><span>Route:</span><span>{selectedFee.route?.routeNumber} - {selectedFee.route?.routeName}</span></div>
              <div className="receipt-row"><span>Fee Month:</span><span>{selectedFee.feeMonth}</span></div>
              <div className="receipt-row"><span>Base Amount:</span><span>{fmt(selectedFee.amount)}</span></div>
              {selectedFee.lateFee > 0 && <div className="receipt-row"><span>Late Fee:</span><span style={{ color: 'var(--danger)' }}>{fmt(selectedFee.lateFee)}</span></div>}
              {selectedFee.discount > 0 && <div className="receipt-row"><span>Discount:</span><span style={{ color: 'var(--success)' }}>-{fmt(selectedFee.discount)}</span></div>}
              <div className="receipt-total"><span>Total Paid:</span><span style={{ color: 'var(--success)' }}>{fmt(selectedFee.totalAmount)}</span></div>
              <div className="receipt-row"><span>Payment Mode:</span><span style={{ textTransform: 'capitalize' }}>{selectedFee.paymentMode}</span></div>
              <div className="receipt-row"><span>Paid On:</span><span>{selectedFee.paidDate}</span></div>
              <div style={{ textAlign: 'center', fontSize: 11, color: 'var(--text-muted)', marginTop: 12 }}>Thank you for your payment!</div>
            </div>
            <button className="btn btn-outline" style={{ width: '100%', marginTop: 12, justifyContent: 'center' }} onClick={() => window.print()}>🖨️ Print Receipt</button>
          </div>
        </div>
      )}
    </div>
  );
}
